BEGIN;

-- Real employee data imported from Filter Results.xlsx + Filter Results (1).xlsx
-- Total: 783 employees (Hyderabad + Kolkata, de-duplicated by email)
-- employee_id : email prefix, dots/specials -> underscore, uppercase
-- role_code   : mapped from Department column (see mapping below)
-- work_mode   : HYBRID (update per employee if needed)
-- password_hash: NULL -> backend falls back to default password123
--
-- Mapping:
--   Cloud Platform Engineering, Global Cloud Services -> DEVOPS
--   Accounting and Finance, Strategic Sourcing        -> FINANCE
--   Human Resources                                   -> HR
--   Product Management                                -> MANAGER
--   Customer Operations, Customer Success, Facilities,
--   Global Services, Managed Services, Services Delivery,
--   Technical Support                                 -> OPS
--   Technology, Information Systems, Legal,
--   Research and Development, <other>                 -> EMPLOYEE

ON CONFLICT (employee_id) DO UPDATE
  SET full_name       = EXCLUDED.full_name,
      email           = EXCLUDED.email,
      department      = EXCLUDED.department,
      role_code       = EXCLUDED.role_code,
      work_mode       = EXCLUDED.work_mode,
      office_location = EXCLUDED.office_location,
      active          = EXCLUDED.active;

COMMIT;